def main():
    os.makedirs("img/blog", exist_ok=True)
    total=len(IMAGES); ok=0; fail=[]
    print(f"Lade {total} Bilder in VOLLAUFLÖSUNG herunter...")
    print("(Vorhandene kleine Bilder werden überschrieben)\n")
    for i,(url,path) in enumerate(IMAGES,1):
        try:
            req=urllib.request.Request(url, headers={"User-Agent":"Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=60) as r:
                data=r.read()
            if len(data)<1000:
                fail.append((path,"zu klein/leer")); print(f"[{i}/{total}] FEHLER (leer): {path}"); continue
            with open(path,"wb") as f:
                f.write(data)
            ok+=1
            kb=len(data)//1024
            print(f"[{i}/{total}] OK: {path} ({kb} KB)")
        except Exception as e:
            fail.append((path,str(e)))
            print(f"[{i}/{total}] FEHLER: {path} -> {e}")
    print(f"\n=== Fertig: {ok}/{total} erfolgreich ===")
    if fail:
        print(f"{len(fail)} fehlgeschlagen:")
        for p,e in fail: print(f"  {p}: {e}")
        print("\nTipp: Skript einfach nochmal ausführen.")

if __name__=="__main__":
    main()
